import { sequelize } from "../db/sequelize.js";
import { User } from "./user.model.js";
import { Partner } from "./partner.model.js";
import { Role } from "./role.model.js";
import { Status } from "./status.model.js";

// --------------------------------------------------------------------------
//  Associations
// --------------------------------------------------------------------------

// --------------------------------------------------------------------------
//  User ↔ Role
// --------------------------------------------------------------------------

User.belongsTo(Role, { foreignKey: "roleId", as: "role" });
Role.hasMany(User, { foreignKey: "roleId", as: "users" });

// --------------------------------------------------------------------------
//  User ↔ Status
// --------------------------------------------------------------------------

User.belongsTo(Status, { foreignKey: "statusId", as: "status" });
Status.hasMany(User, { foreignKey: "statusId", as: "users" });

// --------------------------------------------------------------------------
//  User ↔ Partner (1 : 1)
// --------------------------------------------------------------------------

User.hasOne(Partner, { foreignKey: "userId", as: "partner" });
Partner.belongsTo(User, { foreignKey: "userId", as: "user" });

// --------------------------------------------------------------------------
//  Partner ↔ Status
// --------------------------------------------------------------------------

Partner.belongsTo(Status, { foreignKey: "statusId", as: "status" });
Status.hasMany(Partner, { foreignKey: "statusId", as: "partners" });

// --------------------------------------------------------------------------

export { sequelize, User, Partner, Role, Status };
